#!/usr/bin/env -S npx ts-node -r tsconfig-paths/register
/**
 * Example: OAuth U2M (User-to-Machine) - External Browser
 *
 * Description: For interactive applications where users need to authenticate
 * with SSO. Opens a browser for user authentication.
 *
 * Prerequisites:
 * - OAuth application registered in Databricks
 * - OAuth client ID (no secret needed for U2M)
 * - Redirect URI configured (typically http://localhost:8020)
 *
 * Setup:
 * 1. Register OAuth app in Databricks account console
 * 2. Configure redirect URI to http://localhost:8020
 * 3. Copy the client ID
 *
 * Run:
 * ```bash
 * DATABRICKS_HOST="https://your-workspace.cloud.databricks.com" \
 * DATABRICKS_CLIENT_ID="xxx" \
 * npx ts-node examples/auth/oauth-u2m.ts
 * ```
 */

import {Config, WorkspaceClient} from "@databricks/sdk-experimental";

async function main() {
    const config = new Config({
        host: process.env.DATABRICKS_HOST,
        clientId: process.env.DATABRICKS_CLIENT_ID,
        // OAuth U2M is automatically detected when clientId is provided without clientSecret
    });

    const client = new WorkspaceClient(config);

    try {
        console.log("Opening browser for authentication...");
        console.log("Please complete the authentication flow in your browser.");

        const user = await client.currentUser.me();
        console.log(`✓ Successfully authenticated as: ${user.userName}`);
        console.log(`  User ID: ${user.id}`);
        console.log(`  Email: ${user.emails?.[0]?.value}`);
    } catch (error) {
        console.error("✗ Authentication failed:", error);
        console.error(
            "\nMake sure you have set the following environment variables:"
        );
        console.error("  - DATABRICKS_HOST");
        console.error("  - DATABRICKS_CLIENT_ID");
        process.exit(1);
    }
}

main().catch(console.error);
